import { useEffect, useRef, useState } from "react";
import { clamp, ease } from "./helpers";

export default function TrustSection() {
  const sectionRef = useRef(null);
  const [p, setP] = useState(0);

  useEffect(() => {
    const onScroll = () => {
      const el = sectionRef.current;
      if (!el) return;
      const scrolled = -el.getBoundingClientRect().top;
      const total = el.offsetHeight - window.innerHeight;
      setP(Math.max(0, Math.min(1, scrolled / (total * 0.88))));
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    onScroll();
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const lp = (start, end) => ease(clamp((p - start) / (end - start), 0, 1));

  // Animate the ghost annotations to move up as scroll progresses
  const ghost1Progress = lp(0.1, 0.5);
  const ghost2Progress = lp(0.3, 0.7);

  const serif = "'Playfair Display', 'Georgia', serif";

  return (
    <div ref={sectionRef} style={{ height: "280vh", position: "relative", background: "#fff" }}>
      <div style={{
        position: "sticky",
        top: 0,
        height: "100vh",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        overflow: "hidden",
        padding: "0 8vw",
      }}>

        {/* Main text container */}
        <div style={{
          position: "relative",
          textAlign: "center",
          zIndex: 2,
          maxWidth: 1200,
          margin: "0 auto",
        }}>
          {/* Trust, however is fragile. */}
          <div>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(56px, 9vw, 130px)",
              fontWeight: 900,
              color: "#1a3a6b",
              display: "block",
              lineHeight: 1.0,
              marginBottom: 8,
            }}>Trust,</span>
          </div>
          <div style={{
            display: "flex",
            alignItems: "baseline",
            justifyContent: "center",
            gap: "0.3em",
            flexWrap: "wrap",
            marginBottom: 48,
          }}>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(42px, 7vw, 100px)",
              fontWeight: 400,
              color: "#8b9bb0",
              lineHeight: 1.0,
            }}>however is</span>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(42px, 7vw, 100px)",
              fontWeight: 900,
              color: "#1a1a1a",
              lineHeight: 1.0,
            }}>fragile.</span>
          </div>

          {/* One breach line */}
          <div style={{ marginBottom: 32 }}>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(36px, 6vw, 90px)",
              fontWeight: 900,
              color: "#d93025",
            }}>One breach</span>
          </div>

          {/* One bad experience */}
          <div style={{ marginBottom: 40 }}>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(36px, 6vw, 90px)",
              fontWeight: 900,
              color: "#d93025",
            }}>One bad experience</span>
          </div>

          {/* Footer line */}
          <div>
            <p style={{
              fontSize: "clamp(16px, 1.3vw, 22px)",
              color: "#2c3e4f",
              lineHeight: 1.5,
              fontFamily: "'Inter', system-ui, sans-serif",
              fontWeight: 500,
              margin: 0,
              maxWidth: 600,
              marginLeft: "auto",
              marginRight: "auto",
            }}>
              is all it takes to undo years of hard-earned customer confidence.
            </p>
          </div>
        </div>

        {/* Ghost annotation 1 - slides up from below and overlaps text */}
        <div style={{
          position: "absolute",
          left: "8%",
          top: "35%",
          zIndex: 10,
          pointerEvents: "none",
          background: "rgba(255, 245, 240, 0.92)",
          backdropFilter: "blur(12px)",
          WebkitBackdropFilter: "blur(12px)",
          borderRadius: 20,
          padding: "20px 28px",
          width: 300,
          opacity: Math.min(ghost1Progress * 1.2, 1),
          transform: `translateY(${(1 - ghost1Progress) * 180}px)`,
          transition: "none",
          boxShadow: "0 4px 20px rgba(0,0,0,0.05)",
          border: "1px solid rgba(0,0,0,0.05)",
        }}>
          <p style={{
            fontSize: 14,
            color: "#2d3e50",
            lineHeight: 1.65,
            fontFamily: "'Inter', sans-serif",
            margin: 0,
          }}>
            When speed and scale take priority, due diligence slips and blind spots widen. That's exactly what is happening in the gig economy today.
          </p>
        </div>

        {/* Ghost annotation 2 - slides up from below and overlaps text */}
        <div style={{
          position: "absolute",
          right: "8%",
          top: "55%",
          zIndex: 10,
          pointerEvents: "none",
          background: "rgba(245, 248, 255, 0.92)",
          backdropFilter: "blur(12px)",
          WebkitBackdropFilter: "blur(12px)",
          borderRadius: 20,
          padding: "20px 28px",
          width: 320,
          opacity: Math.min(ghost2Progress * 1.2, 1),
          transform: `translateY(${(1 - ghost2Progress) * 180}px)`,
          transition: "none",
          boxShadow: "0 4px 20px rgba(0,0,0,0.05)",
          border: "1px solid rgba(0,0,0,0.05)",
        }}>
          <p style={{
            fontSize: 14,
            color: "#2d3e50",
            lineHeight: 1.65,
            fontFamily: "'Inter', sans-serif",
            margin: 0,
          }}>
            Identity swaps, impersonation, and hidden criminal histories do more than disrupt operations. They put safety, credibility, and customer trust at risk.
          </p>
        </div>

      </div>
    </div>
  );
}
